 namespace WPAICG\Core\Providers\Google\Methods; if (!defined('ABSPATH')) { exit; } function parse_error_logic_for_response_parser($response_body, int $status_code): string { $message = __('An unknown API error occurred.', 'gpt3-ai-content-generator'); $decoded = is_string($response_body) ? json_decode($response_body, true) : $response_body; if (is_array($decoded) && !empty($decoded['error']['message'])) { $message = $decoded['error']['message']; if (!empty($decoded['error']['details'][0]['message'])) { $message .= " (" . $decoded['error']['details'][0]['message'] . ")"; } } elseif (is_string($response_body)) { $message = substr($response_body, 0, 200); } return trim($message); }